import React from 'react';

const Attendance = () => {
  return (
    <div>
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Attendance Management</h1>
      <div className="bg-white shadow rounded-lg p-6">
        <button className="btn btn-primary mb-4">Mark Attendance</button>
        <p className="text-gray-600">Attendance management features coming soon...</p>
      </div>
    </div>
  );
};

export default Attendance;
